CREATE OR REPLACE FUNCTION total_loans()
    RETURNS TRIGGER 
    AS $$ 
    DECLARE
        target_account_id BIGINT;
    BEGIN 
        -- Determine which account_id to process based on operation type
        IF TG_OP = 'DELETE' THEN
            target_account_id := OLD.account_id;
        ELSE
            target_account_id := NEW.account_id;
        END IF;

        -- Insert or update the loan_summary record
        INSERT INTO loan_summary (account_id, total_loan_count)
        VALUES (
            target_account_id,
            (SELECT COUNT(*) FROM loan WHERE account_id = target_account_id AND status = 'A')
        )
        ON CONFLICT (account_id) 
        DO UPDATE SET 
            total_loan_count = (SELECT COUNT(*) FROM loan WHERE loan.account_id = target_account_id AND status = 'A'),
            last_updated = CURRENT_TIMESTAMP;

        RETURN NEW; 
    END; 
    $$ LANGUAGE plpgsql;

CREATE TRIGGER tr_total_loans 
    AFTER INSERT OR UPDATE OR DELETE OF status 
    ON loan 
    FOR EACH ROW 
    EXECUTE FUNCTION total_loans()

