CREATE OR REPLACE FUNCTION what_quarter_is(date_in DATE, start_month INTEGER)
RETURNS INTEGER AS $$
DECLARE
    month_diff INTEGER;
    adjusted_month INTEGER;
BEGIN
    -- Get the month of the input date
    adjusted_month := EXTRACT(MONTH FROM date_in);

    -- Calculate the difference between the start month and January
    month_diff := (adjusted_month - start_month + 12) % 12;

    -- Calculate which quarter (0-11 months from start_month)
    RETURN FLOOR(month_diff / 3.0) + 1;
END;
$$ LANGUAGE plpgsql;

