CREATE OR REPLACE FUNCTION GapFillInternal(state anyelement, value anyelement) 
RETURNS anyelement AS $$
BEGIN
    IF value IS NOT NULL THEN
        RETURN value;
    ELSE
        RETURN state;
    END IF;
END;
$$ LANGUAGE PLPGSQL;

CREATE OR REPLACE FUNCTION GapFillFinal(state anyelement) 
RETURNS anyelement AS $$
BEGIN
    RETURN state;
END;
$$ LANGUAGE PLPGSQL;

