CREATE OR REPLACE FUNCTION reindex_superhero_hair_colour_ids(IN publisher_id_param BIGINT) 
RETURNS VOID 
LANGUAGE plpgsql 
AS $$
DECLARE
    temp_seq TEXT := 'temp_hair_colour_seq_' || pg_backend_pid();
    rec RECORD;
    new_id INTEGER := 1;
BEGIN
    -- Create a temporary table with ordered superhero records for this publisher
    CREATE TEMP TABLE temp_superhero_order AS
    SELECT id, hair_colour_id
    FROM superhero 
    WHERE publisher_id = publisher_id_param
    ORDER BY id;

    -- Update each record with sequential numbers
    FOR rec IN SELECT id FROM temp_superhero_order ORDER BY id LOOP
        UPDATE superhero 
        SET hair_colour_id = new_id 
        WHERE id = rec.id;
        new_id := new_id + 1;
    END LOOP;

    -- Clean up temporary table
    DROP TABLE temp_superhero_order;
END;
$$

