-- Create a function to check if a category is a business category
CREATE FUNCTION dbo.CheckIsBusinessCategory(@CategoryID INT)
RETURNS BIT
AS
BEGIN
    DECLARE @IsBusiness BIT;
    SELECT @IsBusiness = IsBusinessCategory 
    FROM dbo.EventCategories 
    WHERE ID = @CategoryID;
    RETURN ISNULL(@IsBusiness, 0);
END;

CREATE TABLE [dbo].[BusinessCategories](
    [ID] [int] IDENTITY(1,1) NOT NULL PRIMARY KEY,
    [BusinessCategoryID] [INT] NOT NULL,
    CONSTRAINT FK_BusinessCategories_EventCategories 
        FOREIGN KEY (BusinessCategoryID) REFERENCES EventCategories(ID),
    CONSTRAINT CK_BusinessCategory_IsBusiness 
        CHECK (dbo.CheckIsBusinessCategory(BusinessCategoryID) = 1)
)

DECLARE @InputString NVARCHAR(MAX) = '1.25,5.34,6.9';
DECLARE @Var1 DECIMAL(18,6);
DECLARE @Var2 DECIMAL(18,6);
DECLARE @Var3 DECIMAL(18,6);

-- Using XML parsing method for older SQL Server versions
WITH SplitValues AS (
    SELECT 
        CAST(Split.a.value('.', 'DECIMAL(18,6)') AS DECIMAL(18,6)) as value,
        ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) as rn
    FROM (
        SELECT CAST('<X>'+REPLACE(@InputString,',','</X><X>')+'</X>' AS XML) AS String
    ) AS A
    CROSS APPLY String.nodes('/X') AS Split(a)
)
SELECT 
    @Var1 = MAX(CASE WHEN rn = 1 THEN value END),
    @Var2 = MAX(CASE WHEN rn = 2 THEN value END),
    @Var3 = MAX(CASE WHEN rn = 3 THEN value END)
FROM SplitValues;

-- Display results
SELECT @Var1 as Var1, @Var2 as Var2, @Var3 as Var3

