CREATE OR REPLACE FUNCTION FIND_TEST_TABLE_COLUMN(IN_COLUMN1 TEST_TABLE.COLUMN1%TYPE, IN_COLUMN2 TEST_TABLE.COLUMN2%TYPE, IN_COLUMN3 TEST_TABLE.COLUMN3%TYPE, IN_COLUMN4 TEST_TABLE.COLUMN4%TYPE, IN_REQUESTED_COLUMN VARCHAR2) RETURN VARCHAR2 IS 
    CURSOR C_TEST_TABLE IS 
        SELECT COLUMN1, COLUMN2, COLUMN3, COLUMN4 
        FROM TEST_TABLE 
        WHERE COLUMN1 = IN_COLUMN1 
        AND COLUMN2 = IN_COLUMN2 
        AND COLUMN3 = IN_COLUMN3 
        AND (IN_COLUMN4 IS NULL OR COLUMN4 = IN_COLUMN4);

    C_TEST_TABLE_REC C_TEST_TABLE%ROWTYPE;
    RESULT VARCHAR2(255);
BEGIN 
    OPEN C_TEST_TABLE;
    FETCH C_TEST_TABLE INTO C_TEST_TABLE_REC;

    IF C_TEST_TABLE%FOUND THEN
        IF IN_REQUESTED_COLUMN = 'COLUMN1' THEN 
            RESULT := C_TEST_TABLE_REC.COLUMN1;
        ELSIF IN_REQUESTED_COLUMN = 'COLUMN2' THEN 
            RESULT := C_TEST_TABLE_REC.COLUMN2;
        ELSIF IN_REQUESTED_COLUMN = 'COLUMN3' THEN 
            RESULT := C_TEST_TABLE_REC.COLUMN3;
        ELSIF IN_REQUESTED_COLUMN = 'COLUMN4' THEN 
            RESULT := C_TEST_TABLE_REC.COLUMN4;
        END IF;
    END IF;

    CLOSE C_TEST_TABLE;
    RETURN RESULT;
END

